// Personen kommen als Array im ersten Input
// Aufgaben kommen als Array im zweiten Input
const personen = $input.first().json;
const aufgaben = items.length > 1 ? $input.last().json : [];

// Wenn die Inputs als Arrays kommen
const pList = Array.isArray(personen) ? personen : [personen];
const aList = Array.isArray(aufgaben) ? aufgaben : [aufgaben];

const APP_URL = $env.APP_URL || 'https://ludwig-a11y.github.io/halleluja-os/';
const today = new Date().toISOString().slice(0, 10);

const results = [];

for (const p of pList) {
  if (!p.slack_id) continue;

  // P1-Aufgaben dieser Person
  const meineP1 = aList.filter(a => String(a.pid) === String(p.id));

  if (meineP1.length === 0) {
    // Kein P1 offen
    results.push({
      json: {
        channel: p.slack_id,
        text: `☀️ Guten Morgen, ${p.name}!\n\nKein P1 offen — schau kurz rein ob alles passt:\n<${APP_URL}|Halleluja OS öffnen>`
      }
    });
    continue;
  }

  // Sortiere nach Deadline (früheste zuerst), dann nach Erstellung
  meineP1.sort((a, b) => {
    if (a.dl && b.dl) return a.dl.localeCompare(b.dl);
    if (a.dl) return -1;
    if (b.dl) return 1;
    return 0;
  });

  const top = meineP1[0];
  let dlInfo = '';
  if (top.dl) {
    const dlDate = new Date(top.dl + 'T12:00:00');
    const diff = Math.ceil((dlDate - new Date(today + 'T12:00:00')) / 86400000);
    if (diff === 0) dlInfo = '⏰ Fällig: heute';
    else if (diff === 1) dlInfo = '⏰ Fällig: morgen';
    else if (diff < 0) dlInfo = '🔴 Überfällig seit ' + Math.abs(diff) + ' Tag' + (Math.abs(diff) > 1 ? 'en' : '');
    else dlInfo = '📅 Fällig in ' + diff + ' Tagen';
  }

  const deepLink = `${APP_URL}#task=${top.id}`;
  let msg = `☀️ Guten Morgen, ${p.name}!\n\n🎯 *Deine Top-Priorität heute:*\n> *${top.titel}*`;
  if (dlInfo) msg += `\n> ${dlInfo}`;
  msg += `\n\n<${deepLink}|Hier starten →>`;
  if (meineP1.length > 1) msg += `\n\n_+ ${meineP1.length - 1} weitere P1-Aufgabe${meineP1.length > 2 ? 'n' : ''}_`;

  results.push({ json: { channel: p.slack_id, text: msg } });
}

return results;
